import java.util.*;
import java.util.function.*;
public class App {
    static <T> long countIf(Collection<? extends T> items, Predicate<T> condition) {
        long count = 0;
        for (T item : items) if (condition.test(item)) count++;
        return count;
    }
    public static void main(String[] args) {
        List<Integer> nums = Arrays.asList(1, 3, 7, 2, 8, 9);
        System.out.println("Integers > 5: " + countIf(nums, n -> n > 5));

        Set<String> names = new LinkedHashSet<>(Arrays.asList("Aisha","Raj","Anita","Priya"));
        System.out.println("Strings starting with A: " + countIf(names, s -> s.startsWith("A")));
    }
}

import java.util.*;
abstract class Shape { abstract double area(); }
class Circle extends Shape {
    double radius; Circle(double r) { radius=r; }
    public double area() { return Math.PI * radius * radius; }
}
class Rectangle extends Shape {
    double w, h; Rectangle(double w, double h) { this.w=w; this.h=h; }
    public double area() { return w * h; }
}
public class App {
    static double totalArea(List<? extends Shape> shapes) {
        double total = 0;
        for (Shape s : shapes) total += s.area();  // reads as Shape
        return total;
    }
    public static void main(String[] args) {
        List<Circle>    circles = Arrays.asList(new Circle(5));
        List<Rectangle> rects   = Arrays.asList(new Rectangle(6,10));
        List<Shape>     mixed   = new ArrayList<>();
        mixed.addAll(circles); mixed.addAll(rects);

        System.out.printf("Circles total area: %.2f%n",    totalArea(circles));
        System.out.printf("Rectangles total area: %.2f%n", totalArea(rects));
        System.out.printf("Mixed total area: %.2f%n",      totalArea(mixed));
    }
}

