import java.util.*;
public class App {
    static Optional<Number> maxNumber(List<? extends Number> nums) {
        if (nums.isEmpty()) return Optional.empty();
        Number max = nums.get(0);
        for (Number n : nums) {
            if (n.doubleValue() > max.doubleValue()) max = n;
        }
        return Optional.of(max);
    }
    public static void main(String[] args) {
        System.out.println("Max of ints: "    + maxNumber(Arrays.asList(85, 92, 78, 95, 68)));
        System.out.println("Max of doubles: " + maxNumber(Arrays.asList(2.5, 3.9, 1.1)));
        System.out.println("Max of empty: "   + maxNumber(new ArrayList<>()));
    }
}

