import java.util.*;
class Sorter<T extends Comparable<T>> {
    void sort(List<T> list) {
        Collections.sort(list);
    }
    List<T> sorted(List<? extends T> list) {
        List<T> copy = new ArrayList<>(list);
        Collections.sort(copy);
        return copy;
    }
    static <E extends Comparable<E>> void sortAll(List<? extends List<E>> lists) {
        for (List<E> l : lists) Collections.sort(l);
    }
}
public class App {
    public static void main(String[] args) {
        Sorter<String> strSorter = new Sorter<>();
        List<String> names = new ArrayList<>(Arrays.asList("Raj", "Aisha", "Priya"));
        strSorter.sort(names);
        System.out.println("In-place: " + names);

        List<Integer> ints = Arrays.asList(3, 1, 4, 1, 5);
        Sorter<Integer> intSorter = new Sorter<>();
        System.out.println("New sorted: " + intSorter.sorted(ints));

        List<List<String>> groups = new ArrayList<>();
        groups.add(new ArrayList<>(Arrays.asList("Priya", "Aisha")));
        groups.add(new ArrayList<>(Arrays.asList("Vikram", "Raj")));
        Sorter.sortAll(groups);
        System.out.println("All sorted: " + groups);
    }
}

