exercises.expected_solution:
import java.util.*;
class WildcardCollections {
    static void print(Collection<?> c)                    { System.out.println(c); }
    static double sum(Collection<? extends Number> nums)  {
        double t=0; for (Number n:nums) t+=n.doubleValue(); return t;
    }
    static Object max(Collection<? extends Comparable<?>> c) {
        // Simplified: convert to comparable list
        Object max = null;
        for (Object item : c) {
            if (max == null || ((Comparable<Object>)item).compareTo(max) > 0) max = item;
        }
        return max;
    }
    static void fill(List<? super String> list, String... items) {
        for (String s : items) list.add(s);
    }
    static <T> void copy(List<? super T> dest, List<? extends T> src) {
        for (T item : src) dest.add(item);
    }
    @SafeVarargs
    static <T> void merge(List<? super T> dest, Collection<? extends T>... sources) {
        for (Collection<? extends T> src : sources)
            for (T item : src) dest.add(item);
    }
}
public class App {
    public static void main(String[] args) {
        WildcardCollections.print(Arrays.asList("Aisha","Raj","Priya"));
        System.out.println("Sum: " + WildcardCollections.sum(Arrays.asList(10,20,30)));

        List<Integer> src = Arrays.asList(1, 2, 3);
        List<Number> dest = new ArrayList<>();
        WildcardCollections.copy(dest, src);
        System.out.println("Copied: " + dest);

        List<String> strings = new ArrayList<>();
        WildcardCollections.fill(strings, "hello", "world");
        System.out.println("Filled: " + strings);

        List<String> merged = new ArrayList<>();
        WildcardCollections.merge(merged,
            Arrays.asList("a","b"),
            Arrays.asList("c","d"),
            Arrays.asList("e","f"));
        System.out.println("Merged: " + merged);
    }
}
